e=string p=tonumber x=screen t=0.4 y=0 z=0 E=1 function a(b) c=1 while d[c]do b=e.gsub(b,d[c][2],d[c][1])c=c+1 end c=1 while f[c]do b=e.gsub(b,f[c][2],f[c][1])c=c+1 end g={}h=1 i=0 j=e.find(b,";") while j do g[h]={}k=e.sub(b,i+1,j)l=1 m=0 while m<e.len(k)do o=e.sub(k,m+1,m+8) if o~=";"then c=p("0x"..e.sub(o,1,2))q=p("0x"..e.sub(o,3,4))r=p("0x"..e.sub(o,5,6))s=p("0x"..e.sub(o,7,8)) if s==0 then g[h][l]=false else g[h][l]={c,q,r,s}end end m=m+8 l=l+1 end i=j j=e.find(b,";",j+1)h=h+1 end return g end C=a(H)W={}k=1 while C and C[k]do o,S,L,cr,cg,cb,ca=1,-1,0,-1,-1,-1,-1 while C[k][o]~=nil do P=C[k][o] if P then if P[1]==cr and P[2]==cg and P[3]==cb and P[4]==ca then L=L+1 else if L>0 then W[#W+1]={S,k,L,cr,cg,cb,ca}end S,L,cr,cg,cb,ca=o,1,P[1],P[2],P[3],P[4]end elseif L>0 then W[#W+1]={S,k,L,cr,cg,cb,ca}L=0 end o=o+1 end if L>0 then W[#W+1]={S,k,L,cr,cg,cb,ca}end k=k+1 end function onTick()end function onDraw()if not C then return end for i=1,#W do local c=W[i]x.setColor(c[4]*t,c[5]*t,c[6]*t,c[7]*E)x.drawRectF(y+c[1]-1,z+D-2+c[2],c[3],1)end end

